116	class edge_idx_iterator {
117	  public:
118	    using iterator_category = std::bidirectional_iterator_tag;
119	    using difference_type = std::ptrdiff_t;
120	    using value_type = t_edge_size;
121	    using pointer = t_edge_size*;
122	    using reference = t_edge_size&;
123	
124	    edge_idx_iterator(value_type init)
125	        : value_(init) {}
126	    edge_idx_iterator& operator++() {
127	        value_ += 1;
128	        return *this;
129	    }
130	    edge_idx_iterator& operator--() {
131	        value_ -= 1;
132	        return *this;
133	    }
134	    reference operator*() { return value_; }
135	    pointer operator->() { return &value_; }
136	
137	    friend bool operator==(const edge_idx_iterator& lhs, const edge_idx_iterator& rhs) { return lhs.value_ == rhs.value_; }
138	    friend bool operator!=(const edge_idx_iterator& lhs, const edge_idx_iterator& rhs) { return !(lhs == rhs); }
