386	                }
387	                coordinate_string += std::string(TOTAL_2D_SIDE_STRINGS[node_side]) + ","; //add the side of the routing resource node
388	            }
389	            coordinate_string += ")"; //add the side of the routing resource node
390	            // For OPINs and IPINs the starting and ending coordinate are identical, so we can just arbitrarily assign the start to larger values
391	            // and the end to the lower coordinate
392	            start_x = " (" + std::to_string(node_xhigh(node)) + ","; //start and end coordinates are the same for OPINs and IPINs
393	            start_y = std::to_string(node_yhigh(node)) + ",";
394	            start_layer_str = std::to_string(node_layer_low(node)) + ")";
395	        } else if (node_type(node) == e_rr_type::SOURCE || node_type(node) == e_rr_type::SINK) {
396	            // For SOURCE and SINK the starting and ending coordinate are identical, so just use start
397	            start_x = " (" + std::to_string(node_xhigh(node)) + ",";
398	            start_y = std::to_string(node_yhigh(node)) + ",";
399	            start_layer_str = std::to_string(node_layer_low(node)) + ")";
400	        } else if (node_type(node) == e_rr_type::CHANX || node_type(node) == e_rr_type::CHANY || node_type(node) == e_rr_type::CHANZ) { //for channels, we would like to describe the component with segment specific information
401	            RRIndexedDataId cost_index = node_cost_index(node);
402	            int seg_index = rr_indexed_data_[cost_index].seg_index;
403	            coordinate_string += rr_segments(RRSegmentId(seg_index)).name;       //Write the segment name
404	            coordinate_string += " length:" + std::to_string(node_length(node)); //add the length of the segment
405	            //Figure out the starting and ending coordinate of the segment depending on the direction
406	
407	            arrow = " ->"; //we will point the coordinates from start to finish, left to right
408	
409	            if (node_direction(node) == Direction::DEC) { //signal travels along decreasing direction
410	
411	                start_x = " (" + std::to_string(node_xhigh(node)) + ","; //start coordinates have large value
412	                start_y = std::to_string(node_yhigh(node)) + ",";
413	                start_layer_str = std::to_string(node_layer_high(node)) + ")";
414	                end_x = " (" + std::to_string(node_xlow(node)) + ","; //end coordinates have smaller value
415	                end_y = std::to_string(node_ylow(node)) + ",";
416	                end_layer_str = std::to_string(node_layer_low(node)) + ")";
417	            }
418	
419	            else {                                                      // signal travels in increasing direction, stays at same point, or can travel both directions
420	                start_x = " (" + std::to_string(node_xlow(node)) + ","; //start coordinates have smaller value
421	                start_y = std::to_string(node_ylow(node)) + ",";
422	                start_layer_str = std::to_string(node_layer_low(node)) + ")";
423	                end_x = " (" + std::to_string(node_xhigh(node)) + ","; //end coordinates have larger value
424	                end_y = std::to_string(node_yhigh(node)) + ",";
425	                end_layer_str = std::to_string(node_layer_high(node)) + ")"; //layer number
426	                if (node_direction(node) == Direction::BIDIR) {
427	                    arrow = " <->"; //indicate that signal can travel both direction
428	                }
429	            }
430	        }
431	
432	        coordinate_string += start_x + start_y + start_layer_str; //Write the starting coordinates
433	        coordinate_string += arrow;                               //Indicate the direction
434	        coordinate_string += end_x + end_y + end_layer_str;       //Write the end coordinates
435	        return coordinate_string;
436	    }
